import React, { useState, useEffect } from 'react';
import { View, Text, Button } from 'react-native';
import axios from 'axios';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  const clientId = 'your_client_id';
  const clientSecret = 'your_client_secret';
  const redirectUri = 'your_redirect_uri';
  const authorizationUrl = 'https://oauth2-server.com/authorize';
  const tokenUrl = 'https://oauth2-server.com/token';

  useEffect(() => {
    if (!accessToken) {
      // Step 1: Redirect to the OAuth server for authorization
      const authUrl = `${authorizationUrl}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=read`;
      Linking.openURL(authUrl);
    } else {
      // Step 2: Use the access token to make requests
      axios.get('https://api.example.com/data', {
        headers: { Authorization: `Bearer ${accessToken}` }
      }).then(response => {
        console.log(response.data);
      }).catch(error => {
        if (error.response.status === 401) {
          // Step 3: Refresh the access token
          axios.post(tokenUrl, {
            grant_type: 'refresh_token',
            client_id: clientId,
            client_secret: clientSecret,
            refresh_token: refreshToken
          }, {
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
          }).then(response => {
            setAccessToken(response.data.access_token);
            setRefreshToken(response.data.refresh_token);
          }).catch(error => {
            console.error('Failed to refresh token:', error);
          });
        } else {
          console.error('API request failed:', error);
        }
      });
    }
  }, [accessToken, refreshToken]);

  const handleAuthorization = (url) => {
    // Step 4: Handle the authorization response
    const urlParams = new URLSearchParams(new URL(url).search);
    const code = urlParams.get('code');
    if (code) {
      axios.post(tokenUrl, {
        grant_type: 'authorization_code',
        client_id: clientId,
        client_secret: clientSecret,
        redirect_uri: redirectUri,
        code: code
      }, {
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
      }).then(response => {
        setAccessToken(response.data.access_token);
        setRefreshToken(response.data.refresh_token);
      }).catch(error => {
        console.error('Failed to exchange authorization code for token:', error);
      });
    }
  };

  return (
    <View>
      {accessToken ? (
        <Text>Access Token: {accessToken}</Text>
      ) : (
        <Button title="Authorize" onPress={() => Linking.addEventListener('url', handleAuthorization)} />
      )}
    </View>
  );
};

export default App;